import React, {
  useState,
  useEffect,
  useRef,
  useCallback,
} from "react";
import { useGame } from "../context/GameContext";

// ─── Ball generation helpers ───
function randomPosition(mode) {
  const spread = mode === "precision" ? 6 : 8;
  const x = (Math.random() - 0.5) * spread;
  const y = Math.random() * 3 + 1;
  const z = -(Math.random() * 6 + 3);
  return { x, y, z };
}

function getBallRadius(mode) {
  if (mode === "precision") return 0.15 + Math.random() * 0.1;
  if (mode === "speed") return 0.25 + Math.random() * 0.15;
  return 0.2 + Math.random() * 0.15; // classic
}

function getBallColor() {
  const colors = [
    "#ff4444", "#ff6644", "#ff8800", "#ffaa00",
    "#44ff44", "#44ffaa", "#4488ff", "#aa44ff",
    "#ff44aa", "#ffff44",
  ];
  return colors[Math.floor(Math.random() * colors.length)];
}

function getLifetime(mode) {
  if (mode === "speed") return 1500 + Math.random() * 1000;
  if (mode === "precision") return 3000 + Math.random() * 2000;
  return 2000 + Math.random() * 2000; // classic
}

function getPoints(radius, mode) {
  const base = mode === "precision" ? 150 : mode === "speed" ? 75 : 100;
  // Smaller ball = more points
  return Math.round(base * (0.35 / Math.max(radius, 0.1)));
}

// ─── Main Component ───
function AimTrainer() {
  const { state, dispatch, saveScore } = useGame();
  const { mode, duration } = state.gameSettings;

  // Game state
  const [balls, setBalls] = useState([]);
  const [score, setScore] = useState(0);
  const [hits, setHits] = useState(0);
  const [misses, setMisses] = useState(0);
  const [timeLeft, setTimeLeft] = useState(duration);
  const [gameActive, setGameActive] = useState(false);
  const [gameOver, setGameOver] = useState(false);
  const [countdown, setCountdown] = useState(3);
  const [scoreSaved, setScoreSaved] = useState(false);
  const [hitEffect, setHitEffect] = useState(null); // { x, y, points }

  // Refs
  const sceneRef = useRef(null);
  const timerRef = useRef(null);
  const spawnRef = useRef(null);
  const ballIdRef = useRef(0);

  const accuracy = hits + misses > 0 ? Math.round((hits / (hits + misses)) * 100) : 0;

  // ─── Spawn a ball ───
  const spawnBall = useCallback(() => {
    const pos = randomPosition(mode);
    const radius = getBallRadius(mode);
    const color = getBallColor();
    const lifetime = getLifetime(mode);
    const points = getPoints(radius, mode);
    const id = ++ballIdRef.current;

    const ball = { id, ...pos, radius, color, lifetime, points, createdAt: Date.now() };

    setBalls((prev) => [...prev, ball]);

    // Auto-remove after lifetime
    setTimeout(() => {
      setBalls((prev) => {
        const exists = prev.find((b) => b.id === id);
        if (exists) {
          return prev.filter((b) => b.id !== id);
        }
        return prev;
      });
    }, lifetime);
  }, [mode]);

  // ─── Start game ───
  const startGame = useCallback(() => {
    setScore(0);
    setHits(0);
    setMisses(0);
    setTimeLeft(duration);
    setBalls([]);
    setGameOver(false);
    setScoreSaved(false);
    setCountdown(3);
    setGameActive(false);
    ballIdRef.current = 0;

    // Countdown 3..2..1
    let c = 3;
    const countdownInterval = setInterval(() => {
      c--;
      setCountdown(c);
      if (c <= 0) {
        clearInterval(countdownInterval);
        setCountdown(0);
        setGameActive(true);
      }
    }, 1000);
  }, [duration]);

  // ─── Timer ───
  useEffect(() => {
    if (!gameActive) return;

    timerRef.current = setInterval(() => {
      setTimeLeft((prev) => {
        if (prev <= 1) {
          clearInterval(timerRef.current);
          setGameActive(false);
          setGameOver(true);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timerRef.current);
  }, [gameActive]);

  // ─── Ball spawning ───
  useEffect(() => {
    if (!gameActive) return;

    const spawnRate = mode === "speed" ? 400 : mode === "precision" ? 1200 : 700;
    spawnBall(); // spawn first immediately

    spawnRef.current = setInterval(spawnBall, spawnRate);

    return () => clearInterval(spawnRef.current);
  }, [gameActive, spawnBall, mode]);

  // ─── Cleanup balls when game ends ───
  useEffect(() => {
    if (gameOver) {
      setBalls([]);
      clearInterval(spawnRef.current);
    }
  }, [gameOver]);

  // ─── Auto-save score on game over ───
  useEffect(() => {
    if (gameOver && !scoreSaved && score > 0) {
      saveScore({
        score,
        hits,
        misses,
        accuracy,
        mode,
        duration,
      });
      setScoreSaved(true);
    }
  }, [gameOver, scoreSaved, score, hits, misses, accuracy, mode, duration, saveScore]);

  // ─── Handle shot (click on ball) ───
  const handleBallClick = useCallback((ballId, points, event) => {
    // Stop propagation so the scene miss handler doesn't fire
    if (event) event.stopPropagation();

    setBalls((prev) => prev.filter((b) => b.id !== ballId));
    setScore((prev) => prev + points);
    setHits((prev) => prev + 1);

    // Hit effect
    setHitEffect({ x: Math.random() * 80 + 10, y: Math.random() * 60 + 10, points });
    setTimeout(() => setHitEffect(null), 600);
  }, []);

  // ─── Handle miss (click on empty space) ───
  const handleSceneMiss = useCallback(() => {
    if (!gameActive) return;
    setMisses((prev) => prev + 1);
  }, [gameActive]);

  // ─── Init scene ───
  useEffect(() => {
    startGame();
    // eslint-disable-next-line
  }, []);

  // ─── Register A-Frame click handlers ───
  useEffect(() => {
    if (!sceneRef.current) return;

    const scene = sceneRef.current;

    // Handle clicks on the scene (misses)
    const onSceneClick = (e) => {
      // Only count as miss if we didn't click a ball
      if (e.target === scene || e.target.tagName === "A-SKY" || e.target.tagName === "A-PLANE") {
        handleSceneMiss();
      }
    };
    scene.addEventListener("click", onSceneClick);

    return () => {
      scene.removeEventListener("click", onSceneClick);
    };
  }, [handleSceneMiss]);

  // ─── Click handler for balls via data attributes ───
  useEffect(() => {
    if (!sceneRef.current) return;
    const scene = sceneRef.current;

    const onBallClick = (e) => {
      const el = e.target.closest("[data-ball-id]");
      if (el) {
        const ballId = parseInt(el.getAttribute("data-ball-id"), 10);
        const points = parseInt(el.getAttribute("data-ball-points"), 10);
        handleBallClick(ballId, points, e);
      }
    };

    scene.addEventListener("click", onBallClick);
    return () => scene.removeEventListener("click", onBallClick);
  }, [handleBallClick]);

  return (
    <div className="aim-trainer">
      {/* ─── HUD Overlay ─── */}
      <div className="hud">
        <div className="hud-left">
          <div className="hud-item">
            <span className="hud-label">Score</span>
            <span className="hud-value score-val">{score}</span>
          </div>
          <div className="hud-item">
            <span className="hud-label">Accuracy</span>
            <span className="hud-value">{accuracy}%</span>
          </div>
        </div>

        <div className="hud-center">
          {/* Conditional rendering for countdown / timer */}
          {countdown > 0 && (
            <div className="countdown-display">{countdown}</div>
          )}
          {countdown <= 0 && !gameOver && (
            <div className={`timer-display ${timeLeft <= 5 ? "timer-danger" : ""}`}>
              {timeLeft}
            </div>
          )}
        </div>

        <div className="hud-right">
          <div className="hud-item">
            <span className="hud-label">Hits</span>
            <span className="hud-value hit-val">{hits}</span>
          </div>
          <div className="hud-item">
            <span className="hud-label">Mode</span>
            <span className="hud-value mode-val">{mode}</span>
          </div>
        </div>
      </div>

      {/* ─── Hit effect ─── */}
      {hitEffect && (
        <div
          className="hit-effect"
          style={{ left: `${hitEffect.x}%`, top: `${hitEffect.y}%` }}
        >
          +{hitEffect.points}
        </div>
      )}

      {/* ─── Crosshair ─── */}
      {gameActive && <div className="crosshair" />}

      {/* ─── 3D Scene ─── */}
      <div className="scene-container">
        <a-scene
          ref={sceneRef}
          embedded
          vr-mode-ui="enabled: false"
          cursor="rayOrigin: mouse; fuse: false"
          raycaster="objects: .ball-target"
          style={{ width: "100%", height: "100%" }}
        >
          {/* Lighting */}
          <a-light type="ambient" color="#334" intensity="0.4" />
          <a-light type="directional" color="#fff" intensity="0.8" position="2 8 3" />
          <a-light type="point" color="#ff4444" intensity="0.3" position="0 3 -5" />
          <a-light type="point" color="#4488ff" intensity="0.2" position="-4 2 -3" />

          {/* Environment — dark shooting range */}
          <a-sky color="#0a0a12" />
          <a-plane
            rotation="-90 0 0"
            width="30"
            height="30"
            color="#111118"
            position="0 0 -5"
          />

          {/* Back wall */}
          <a-plane
            position="0 3 -10"
            width="30"
            height="12"
            color="#0d0d18"
          />

          {/* Grid lines on floor */}
          {Array.from({ length: 11 }).map((_, i) => (
            <a-entity key={`grid-${i}`}>
              <a-box
                position={`${(i - 5) * 3} 0.01 -5`}
                width="0.02"
                height="0.02"
                depth="30"
                color="#1a1a2e"
              />
            </a-entity>
          ))}

          {/* Camera — locked so user can only point and click */}
          <a-camera
            position="0 1.8 0"
            look-controls="enabled: true; pointerLockEnabled: true"
            wasd-controls="enabled: false"
          />

          {/* ─── Balls ─── (array mapping) */}
          {balls.map((ball) => (
            <a-sphere
              key={ball.id}
              class="ball-target"
              data-ball-id={ball.id}
              data-ball-points={ball.points}
              position={`${ball.x} ${ball.y} ${ball.z}`}
              radius={ball.radius}
              color={ball.color}
              metalness="0.3"
              roughness="0.4"
              animation={`property: position; to: ${ball.x + (Math.random() - 0.5) * 2} ${ball.y + (Math.random() - 0.5)} ${ball.z}; dur: ${ball.lifetime}; easing: easeInOutSine`}
              animation__pulse={`property: scale; from: 0 0 0; to: 1 1 1; dur: 200; easing: easeOutBack`}
            />
          ))}
        </a-scene>
      </div>

      {/* ─── Game Over screen ─── */}
      {gameOver && (
        <div className="game-over-overlay">
          <div className="game-over-card">
            <h2 className="game-over-title">TRAINING COMPLETE</h2>
            <div className="stats-grid">
              <div className="stat-item">
                <span className="stat-label">Final Score</span>
                <span className="stat-value big">{score}</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Hits</span>
                <span className="stat-value">{hits}</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Misses</span>
                <span className="stat-value">{misses}</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Accuracy</span>
                <span className="stat-value">{accuracy}%</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Mode</span>
                <span className="stat-value">{mode}</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Duration</span>
                <span className="stat-value">{duration}s</span>
              </div>
            </div>

            {/* Conditional — accuracy feedback */}
            {accuracy >= 80 && (
              <p className="feedback good">🎯 Excellent accuracy! Sharpshooter!</p>
            )}
            {accuracy >= 50 && accuracy < 80 && (
              <p className="feedback ok">👍 Good aim, keep practicing!</p>
            )}
            {accuracy < 50 && accuracy > 0 && (
              <p className="feedback bad">😤 Keep training, you'll get better!</p>
            )}
            {accuracy === 0 && (
              <p className="feedback bad">🤔 Did you even try?</p>
            )}

            {scoreSaved && (
              <p className="score-saved-msg">✅ Score saved!</p>
            )}

            <div className="game-over-actions">
              <button className="btn-primary" onClick={startGame}>
                🔄 Play Again
              </button>
              <button
                className="btn-secondary"
                onClick={() => dispatch({ type: "SET_PAGE", payload: "home" })}
              >
                🏠 Home
              </button>
              <button
                className="btn-secondary"
                onClick={() =>
                  dispatch({ type: "SET_PAGE", payload: "leaderboard" })
                }
              >
                🏆 Leaderboard
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ─── Back button (top-left, only during game) ─── */}
      {!gameOver && (
        <button
          className="back-btn"
          onClick={() => {
            clearInterval(timerRef.current);
            clearInterval(spawnRef.current);
            dispatch({ type: "SET_PAGE", payload: "home" });
          }}
        >
          ✕
        </button>
      )}
    </div>
  );
}

export default AimTrainer;
